<section class="content-header"><h1>Proyeksi Kas per Bulan <small>Finance Reports</small></h1><ol class="breadcrumb"><li><a href="<?=base_index();?>"><i class="fa fa-dashboard"></i> Home</a></li><li><a href="<?=base_index();?>finance-report">Finance Reports</a></li><li class="active">Proyeksi Kas per Bulan</li></ol></section>
<section class="content"><div class="box box-primary"><div class="box-header with-border"><h3 class="box-title">Monthly Cash Projection</h3><div class="box-tools"><button id="btn_excel" class="btn btn-success btn-sm"><i class="fa fa-file-excel-o"></i> Export Excel</button> <button id="btn_print" class="btn btn-default btn-sm"><i class="fa fa-print"></i> Print/PDF</button></div></div><div class="box-body">
<form id="form_cpm" class="form-horizontal cpm-toolbar"><div class="form-group"><label class="control-label col-md-2">Start Month</label><div class="col-md-2"><input type="month" id="start_month" name="start_month" class="form-control" value="<?=date('Y-m');?>"></div><label class="control-label col-md-2">Jumlah Bulan</label><div class="col-md-2"><input type="number" id="number_of_months" name="number_of_months" class="form-control" value="5" min="1" max="24"></div><div class="col-md-4"><button type="submit" id="btn_filter" class="btn btn-primary"><i class="fa fa-search"></i> Tampilkan</button></div></div></form>
