<div class="row"><div class="col-md-3"><div class="cpm-card"><h4>Opening Cash</h4><div id="cpm_opening" class="cpm-value">0.00</div></div></div><div class="col-md-3"><div class="cpm-card"><h4>Total Inflow</h4><div id="cpm_inflow" class="cpm-value text-green">0.00</div></div></div><div class="col-md-3"><div class="cpm-card"><h4>Total Outflow</h4><div id="cpm_outflow" class="cpm-value text-red">0.00</div></div></div><div class="col-md-3"><div class="cpm-card"><h4>Ending Cash</h4><div id="cpm_ending" class="cpm-value">0.00</div></div></div></div>
