<script>
$(function(){var cpmChart=null;function num(v){v=parseFloat(v||0);return v.toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2});}function renderChart(chart){var ctx=document.getElementById('cpm_chart').getContext('2d');if(cpmChart&&cpmChart.destroy)cpmChart.destroy();cpmChart=new Chart(ctx).Line({labels:chart.labels,datasets:[{label:'Ending Cash',fillColor:'rgba(15,118,110,0.12)',strokeColor:'#0f766e',pointColor:'#0f766e',pointStrokeColor:'#fff',data:chart.ending},{label:'Inflow',fillColor:'rgba(34,197,94,0.12)',strokeColor:'#16a34a',pointColor:'#16a34a',pointStrokeColor:'#fff',data:chart.inflow},{label:'Outflow',fillColor:'rgba(239,68,68,0.10)',strokeColor:'#dc2626',pointColor:'#dc2626',pointStrokeColor:'#fff',data:chart.outflow}]},{responsive:true,maintainAspectRatio:false,bezierCurve:false,datasetFill:false});}
function qs(){return $('#form_cpm').serialize();}function loadReport(){$('#cpm_alert').hide().text('');$('#cpm_result').html('<div class="text-center" style="padding:30px"><i class="fa fa-spinner fa-spin fa-2x"></i><br>Loading...</div>');$('#btn_filter').prop('disabled',true);$.ajax({url:'<?=base_admin();?>modul/finance_report/finance_report_proyeksi_kas_per_bulan_action.php?act=filter',type:'POST',dataType:'json',data:qs()}).done(function(res){if(res.status==='success'){$('#cpm_result').html(res.html);$('#cpm_warning').html(res.warning_html||'');$('#cpm_opening').text(num(res.summary.opening_cash));$('#cpm_inflow').text(num(res.summary.total_inflow));$('#cpm_outflow').text(num(res.summary.total_outflow));$('#cpm_ending').text(num(res.summary.ending_cash));renderChart(res.chart);}else{$('#cpm_result').html('<div class="alert alert-danger">'+(res.message||'Laporan gagal diproses.')+'</div>');$('#cpm_alert').text(res.message||'Laporan gagal diproses.').show();}}).fail(function(xhr){$('#cpm_result').html('<div class="alert alert-danger">Server error</div>');$('#cpm_alert').text(xhr.responseText||'Server error').show();}).always(function(){$('#btn_filter').prop('disabled',false);});}
$('#form_cpm').on('submit',function(e){e.preventDefault();loadReport();});$('#btn_excel').on('click',function(){window.location='<?=base_admin();?>modul/finance_report/finance_report_proyeksi_kas_per_bulan_action.php?act=excel&'+qs();});$('#btn_print').on('click',function(){window.open('<?=base_admin();?>modul/finance_report/finance_report_proyeksi_kas_per_bulan_action.php?act=print&'+qs(),'_blank');});loadReport();});
</script>
